import React, { useEffect, useState } from "react";
import { Plus, Trash2, Upload, X, Zap } from "lucide-react";
import axios from "axios";

const API_BASE = "/api"; // change to your FastAPI route prefix

const SOURCE_TYPES = [
  { value: "rss", label: "RSS Feed" },
  { value: "pdf", label: "PDF Upload" },
  { value: "api", label: "API/Provider" },
];
const API_PROVIDERS = [
  { value: "tavily", label: "Tavily" },
  // More later
];

const Sources = () => {
  const [sources, setSources] = useState([]);
  const [uploadedFiles, setUploadedFiles] = useState([]);
  const [showAddSource, setShowAddSource] = useState(false);
  const [addType, setAddType] = useState("rss");
  const [addProvider, setAddProvider] = useState("tavily");
  const [addQuery, setAddQuery] = useState("");
  const [addUrl, setAddUrl] = useState("");
  const [addName, setAddName] = useState("");
  const [addFile, setAddFile] = useState(null);
  const [error, setError] = useState("");

  // ====================== Fetch data ===========================
  useEffect(() => {
    fetchSources();
    fetchFiles();
  }, []);

  async function fetchSources() {
    try {
      const token = localStorage.getItem("token"); // Your auth system
      const res = await axios.get(`${API_BASE}/sources/`, {
        headers: { Authorization: `Bearer ${token}` },
      });
      setSources(res.data);
    } catch (e) {
      setError("Failed to fetch sources.");
    }
  }

  async function fetchFiles() {
    try {
      const token = localStorage.getItem("token");
      const res = await axios.get(`${API_BASE}/files/`, {
        headers: { Authorization: `Bearer ${token}` },
      });
      setUploadedFiles(res.data);
    } catch (e) {
      setUploadedFiles([]);
    }
  }

  // ====================== Add Source ===========================
  async function handleAddSource(e) {
    e.preventDefault();
    setError("");

    try {
      const token = localStorage.getItem("token");

      if (addType === "pdf") {
        // Upload file, then create source referencing uploaded file
        if (!addFile) {
          setError("Choose a PDF file.");
          return;
        }
        const fileData = new FormData();
        fileData.append("uploaded_file", addFile);
        const fRes = await axios.post(`${API_BASE}/files/`, fileData, {
          headers: { Authorization: `Bearer ${token}` },
        });
        // File upload will auto-create the source on backend
        fetchSources();
        fetchFiles();
        setShowAddSource(false);
        resetAdd();
        return;
      }

      // RSS or API
      let body = { name: addName, type: addType, active: true };
      if (addType === "rss") body.url = addUrl;
      if (addType === "api") {
        body.provider = addProvider;
        body.query = addQuery;
      }
      await axios.post(`${API_BASE}/sources/`, body, {
        headers: { Authorization: `Bearer ${token}` },
      });
      fetchSources();
      setShowAddSource(false);
      resetAdd();
    } catch (e) {
      setError(e?.response?.data?.detail || "Failed to add source.");
    }
  }

  function resetAdd() {
    setAddType("rss");
    setAddProvider("tavily");
    setAddQuery("");
    setAddUrl("");
    setAddName("");
    setAddFile(null);
    setError("");
  }

  // =================== Delete Source ===========================
  async function handleDeleteSource(id) {
    if (!window.confirm("Delete this source?")) return;
    const token = localStorage.getItem("token");
    try {
      await axios.delete(`${API_BASE}/sources/${id}`, {
        headers: { Authorization: `Bearer ${token}` },
      });
      setSources(sources.filter(s => s.id !== id));
    } catch (e) {
      setError("Delete failed.");
    }
  }

  // =============== Toggle Source Active ========================
  async function handleToggleActive(id) {
    const token = localStorage.getItem("token");
    try {
      await axios.patch(`${API_BASE}/sources/${id}/activate`, {}, {
        headers: { Authorization: `Bearer ${token}` },
      });
      fetchSources();
    } catch (e) {
      setError("Failed to toggle.");
    }
  }

  // =================== Delete File =============================
  async function handleDeleteFile(id) {
    // Add file delete logic if you implement backend for it
  }

  // =================== Render UI ===============================
  const apiSources = sources.filter(s => s.type === "api");
  return (
    <div className="p-6 space-y-6">
      {error && <div className="bg-red-100 text-red-700 rounded p-3">{error}</div>}

      {/* ========== List All Sources ========== */}
      <div className="bg-white rounded-lg shadow p-6">
        <div className="flex items-center justify-between mb-6">
          <h3 className="text-lg font-semibold">Sources</h3>
          <button
            onClick={() => setShowAddSource(true)}
            className="px-4 py-2 bg-blue-600 text-white rounded-lg hover:bg-blue-700 flex items-center gap-2"
          >
            <Plus className="w-4 h-4" />
            Add Source
          </button>
        </div>
        <div className="space-y-3">
          {sources.map(source => (
            <div key={source.id} className="flex items-center justify-between p-4 border rounded-lg">
              <div>
                <p className="font-medium text-gray-900 flex items-center gap-2">
                  {source.type === "rss" && <Zap className="w-4 h-4 text-blue-500" />}
                  {source.type === "pdf" && <Upload className="w-4 h-4 text-purple-500" />}
                  {source.type === "api" && <span className="px-2 py-0.5 rounded text-xs bg-yellow-100 text-yellow-700">API</span>}
                  {source.name}
                </p>
                {source.type === "rss" && <p className="text-sm text-gray-500">{source.url}</p>}
                {source.type === "pdf" && <p className="text-sm text-gray-500">PDF: {source.file_path}</p>}
                {source.type === "api" && (
                  <>
                    <p className="text-sm text-gray-500">Provider: {source.provider}</p>
                    <p className="text-sm text-gray-500">Query: {source.query}</p>
                  </>
                )}
                {source.last_synced && (
                  <p className="text-xs text-gray-400 mt-1">Last sync: {new Date(source.last_synced).toLocaleString()}</p>
                )}
              </div>
              <div className="flex items-center gap-2">
                <label className="relative inline-flex items-center cursor-pointer">
                  <input
                    type="checkbox"
                    checked={source.active}
                    onChange={() => handleToggleActive(source.id)}
                    className="sr-only peer"
                  />
                  <div className="w-11 h-6 bg-gray-200 peer-focus:outline-none peer-focus:ring-4 peer-focus:ring-blue-300 rounded-full peer peer-checked:after:translate-x-full peer-checked:after:border-white after:content-[''] after:absolute after:top-[2px] after:left-[2px] after:bg-white after:rounded-full after:h-5 after:w-5 after:transition-all peer-checked:bg-blue-600"></div>
                </label>
                <button className="p-2 text-red-600 hover:bg-red-50 rounded" onClick={() => handleDeleteSource(source.id)}>
                  <Trash2 className="w-4 h-4" />
                </button>
              </div>
            </div>
          ))}
        </div>
      </div>

      {/* ========== Add Source Modal ========== */}
      {showAddSource && (
        <div className="fixed inset-0 z-50 bg-black bg-opacity-20 flex items-center justify-center">
          <div className="bg-white p-8 rounded-lg shadow-lg min-w-[350px] max-w-md">
            <h3 className="text-lg font-semibold mb-4">Add Source</h3>
            <form onSubmit={handleAddSource}>
              <label className="block mb-2 font-medium text-sm">Source Type</label>
              <select
                value={addType}
                onChange={e => setAddType(e.target.value)}
                className="w-full mb-4 border rounded p-2"
              >
                {SOURCE_TYPES.map(t => <option value={t.value} key={t.value}>{t.label}</option>)}
              </select>

              <label className="block mb-2 font-medium text-sm">Name</label>
              <input
                className="w-full border rounded p-2 mb-4"
                value={addName}
                onChange={e => setAddName(e.target.value)}
                required
                placeholder="e.g. Forrester, OpenAI Blog"
              />

              {/* RSS URL */}
              {addType === "rss" && (
                <>
                  <label className="block mb-2 font-medium text-sm">Feed URL</label>
                  <input
                    className="w-full border rounded p-2 mb-4"
                    value={addUrl}
                    onChange={e => setAddUrl(e.target.value)}
                    required
                    placeholder="https://example.com/feed"
                  />
                </>
              )}

              {/* API Provider & Query */}
              {addType === "api" && (
                <>
                  <label className="block mb-2 font-medium text-sm">Provider</label>
                  <select
                    value={addProvider}
                    onChange={e => setAddProvider(e.target.value)}
                    className="w-full mb-4 border rounded p-2"
                  >
                    {API_PROVIDERS.map(p => <option value={p.value} key={p.value}>{p.label}</option>)}
                  </select>
                  <label className="block mb-2 font-medium text-sm">Query</label>
                  <input
                    className="w-full border rounded p-2 mb-4"
                    value={addQuery}
                    onChange={e => setAddQuery(e.target.value)}
                    required
                    placeholder="AI trends, etc."
                  />
                </>
              )}

              {/* PDF Upload */}
              {addType === "pdf" && (
                <>
                  <label className="block mb-2 font-medium text-sm">PDF File</label>
                  <input
                    type="file"
                    accept=".pdf"
                    className="w-full border rounded p-2 mb-4"
                    onChange={e => setAddFile(e.target.files[0])}
                    required
                  />
                </>
              )}

              <div className="flex justify-end gap-3">
                <button type="button" onClick={() => { setShowAddSource(false); resetAdd(); }} className="px-4 py-2 border border-gray-300 rounded-lg hover:bg-gray-50">Cancel</button>
                <button type="submit" className="px-4 py-2 bg-blue-600 text-white rounded-lg hover:bg-blue-700">Add Source</button>
              </div>
            </form>
          </div>
        </div>
      )}

      {/* ========== Uploaded Files ========== */}
      <div className="bg-white rounded-lg shadow p-6">
        <h3 className="text-lg font-semibold mb-4">Uploaded PDFs</h3>
        <div className="space-y-2">
          {uploadedFiles.length === 0 && <p className="text-gray-400 text-sm">No files uploaded yet.</p>}
          {uploadedFiles.map(file => (
            <div key={file.id} className="flex items-center justify-between p-3 bg-gray-50 rounded">
              <div>
                <p className="text-sm font-medium">{file.filename}</p>
                <p className="text-xs text-gray-500">
                  Uploaded: {new Date(file.upload_date).toLocaleString()} • Status: {file.status}
                </p>
              </div>
              {/* <button className="text-red-600 hover:bg-red-50 p-1 rounded" onClick={() => handleDeleteFile(file.id)}>
                <X className="w-4 h-4" />
              </button> */}
            </div>
          ))}
        </div>
      </div>

      {/* ========== Paid Sources Integration ========== */}
      <div className="bg-white rounded-lg shadow p-6">
        <h3 className="text-lg font-semibold mb-4">Paid Sources Integration</h3>
        <div className="space-y-3">
          {apiSources.length === 0 && <p className="text-gray-400 text-sm">No API sources added.</p>}
          {apiSources.map(api => (
            <div key={api.id} className="p-4 border rounded-lg flex items-center justify-between">
              <div>
                <p className="font-medium">{api.name}</p>
                <p className="text-sm text-gray-500">Provider: {api.provider}</p>
                <p className="text-sm text-gray-500">Query: {api.query}</p>
              </div>
              <span className={`px-3 py-1 rounded-full text-sm ${
                api.active ? 'bg-green-100 text-green-700' : 'bg-gray-100 text-gray-700'
              }`}>
                {api.active ? "Connected" : "Not Connected"}
              </span>
            </div>
          ))}
        </div>
      </div>
    </div>
  );
};

export default Sources;
